VALUES
  ('optometrist-moex-00604', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關低視力者輔助器具下列敘述何者正確？①視覺障礙者使用的輔具依感官媒介可區分為視覺輔具、觸覺', '["驗光人員法所稱低視力者輔助器具，指以驗光輔助視覺功能之各式光學器具", "低視 力者輔助器具中的光學輔具是指利用光學原理擴大角膜屈光的設施或工具", "低視力者輔助器具之教導 使用屬於驗光師之業務範圍  ⑤放大鏡作為助視器的原理是利用尺寸放大，透過物體在視網膜上形成放大 的像，使更多的感光細胞產生刺激從而改善視覺效果", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00605', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光所的執業人員之規定，下列何者正確？①驗光所執行業務之紀錄及醫師開具之照會單或醫囑單，', '["驗光所轉介至醫療機構診治時，所填具之轉介單，必須至少保存 3 年", "驗光所未依法保存驗光紀錄，可處新臺幣1萬元以上5萬元以下罰鍰", "驗光人員執行業務，應製作紀 錄，並應依當事人要求，予以提供驗光結果報告，並必須加註驗光人員證書號碼", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00606', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光人員執行業務，發現視力不能矯正至正常者，應該如何處理？', '["轉介至醫療機構診治", "逕行教導使用低視力輔助器具", "逕予一般眼鏡之配鏡", "遊說購買健康食品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00607', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關成人之一般隱形眼鏡，下列敘述何者正確？', '["驗光師可以配鏡及驗光", "驗光師可以配鏡但不能驗光", "驗光師不能配鏡但可以驗光", "驗光師不能配鏡及驗光"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00608', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '醫療法所稱醫療廣告，必須符合下列那些規範？①非醫療機構，不得為醫療廣告  ②利用廣播、電視之醫', '["醫療廣告應先經所在地直轄市或縣（市）主管機關核准", "得摘錄醫學 刊物內容為宣傳", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00609', 'optometrist', 'optometrist-moex-112-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光師執業應接受繼續教育之規定，下列敘述何者正確？①繼續教育應包括專業倫理及專業相關法規之', '["領得驗光師證書逾5年首次申請執業登記，得以前1年內接受繼續教育課程總積分達六分之一以上 之證明文件代之", "繼續教育之課程，除了感染管制及性別議題之外，專業之積分每6年應至少達96點以上", "於澎湖、金門、馬祖、綠島、蘭嶼等離島地區執業者，其繼續教育課程之積分1點得以1.5點計", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "47389aa2fc18", "answer_pdf_sha1": "723eb96326a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 50, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00610', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '當水平聚焦線（horizontalfocalline）比垂直聚焦線（verticalfocalline）靠近眼球前端時，這是何種散 光，而平K（flatK）值位於那一子午線？', '["逆規（against-the-rule）；水平子午線（horizontalmeridian）", "順規（with-the-rule）；垂直子午線（verticalmeridian）", "逆規（against-the-rule）；垂直子午線（verticalmeridian）", "順規（with-the-rule）；水平子午線（horizontalmeridian）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00611', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一患者視力為0.4，若此視標為4公尺用視標，請問其視標高度為何？', '["2.328mm", "8.73mm", "14.55mm", "18.61mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
