  ('optometrist-moex-00613', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '患者右眼前方放置紅色片（redlenstest），看到紅光點在他的右下方，則患者有：', '["右眼上外隱斜位", "右眼下內隱斜位", "左眼上內隱斜位", "右眼上內隱斜位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
